mapper.update:
UPDATE openplatform_app_t
icon_id = #{iconId,jdbcType=VARCHAR}, app_name_cn = #{appNameCn,jdbcType=VARCHAR}, app_name_en = #{appNameEn,jdbcType=VARCHAR}, app_desc_cn = #{appDescCn,jdbcType=VARCHAR}, app_desc_en = #{appDescEn,jdbcType=VARCHAR}, app_type = #{appType,jdbcType=INTEGER}, app_sub_type = #{appSubType,jdbcType=INTEGER}, status = #{status,jdbcType=INTEGER}, last_update_by = #{lastUpdateBy,jdbcType=VARCHAR}, last_update_time = NOW(3)
WHERE app_id = #{appId,jdbcType=VARCHAR}

mapper.delete:
DELETE
FROM openplatform_app_p_t
WHERE parent_id = #{parentId,jdbcType=BIGINT}
  AND property_name = #{propertyName,jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(1)
FROM openplatform_app_p_t
WHERE property_name = #{propertyName,jdbcType=VARCHAR}
  AND property_value = #{propertyValue,jdbcType=VARCHAR}
  AND status = 1

SELECT value
FROM openplatform_property_t
WHERE path = #{path}
  AND code = #{code}
  AND status = 1
